// 1. Grab inputs
const createdAtRaw = $('Get Last Created').first().json.created_at; 
const defaultDate = "2026-01-01";

// 2. Setup "Today" at midnight for comparison
const today = new Date();
today.setHours(0, 0, 0, 0);

let since;

const createdAtDate = new Date(createdAtRaw);

// Create a copy of createdAtDate set to midnight to compare only the calendar date
const createdAtMidnight = new Date(createdAtDate);
createdAtMidnight.setHours(0, 0, 0, 0);

if (createdAtMidnight <= today) {
    // Scenario: Date is strictly in the past (yesterday or older)
    since = createdAtDate.toISOString().split('T')[0];
} else {
    // Scenario: Date is Today or in the future
    since = defaultDate;
}

// Return the appropriate values
return { since };

const raw = $input.first().json.textContent;
if (!raw) throw new Error('textContent field is empty or missing');

const inputText = raw.replace(/\\n/g, '\n').replace(/\\t/g, '\t');
const now = new Date();
const posted = now.toISOString().split('T')[0] + ' ' + now.toTimeString().split(' ')[0];

const jobs = [];
const seenUrls = new Set();

const noisePhrases = [
  "suchergebnisse anzeigen", "aktiv auf suche", "offen für angebote", 
  "suche gerade nichts", "jobbenachrichtigungen verwalten", "abbestellen", 
  "hilfe", "impressum", "datenschutz", "profil anzeigen"
];

const cleanUrl = (url) => {
  if (!url) return null;
  let cleaned = url.trim().replace(/[.,;)\]]+$/, '').split('?')[0];
  if (cleaned.includes('linkedin.com')) {
    const m = cleaned.match(/linkedin\.com(?:\/comm)?\/jobs\/view\/(\d+)/);
    if (m) return `https://www.linkedin.com/jobs/view/${m[1]}/`;
  }
  return cleaned;
};

const blocks = inputText.split(/(?:-{10,}|~{10,})/);

for (let block of blocks) {
  const lines = block.split('\n').map(l => l.trim()).filter(l => l.length > 0);
  if (lines.length < 2) continue;

  const blockText = lines.join(' ');
  let extracted = {};

  // ── LINKEDIN ─────────────────────────────────────────────────────────────
  if (blockText.includes('linkedin.com')) {
    const urlMatch = block.match(/(https:\/\/www\.linkedin\.com\/(?:comm\/)?jobs\/view\/\d+[^\s\n]*)/);
    if (!urlMatch) continue;

    const dataLines = lines.filter(l => 
      !l.match(/Jobangebot ansehen|Stelle ansehen|View job|Dieses Unternehmen|Jobs via/i) &&
      !l.startsWith('http')
    );

    extracted = {
      title: dataLines[0],
      company: dataLines[1],
      location: dataLines[2],
      url: cleanUrl(urlMatch[1]),
      via: 'linkedin'
    };
  }

  // ── XING ───────────────────────────────────────────────────────────────
  else if (blockText.includes('xing.com')) {
    const urlMatch = block.match(/=>\s*(https:\/\/www\.xing\.com\/m\/[^\s\n]+)/);
    if (!urlMatch) continue;

    const urlLineIndex = lines.findIndex(l => l.includes('=>'));
    let title = lines[urlLineIndex - 1] || "";

    if (title.includes("Zu den Ersten") && urlLineIndex > 1) {
      title = lines[urlLineIndex - 2]; 
    }

    extracted = {
      title: title.replace(':', ''),
      company: lines[urlLineIndex + 1],
      location: lines[urlLineIndex + 2],
      salary: lines.find(l => l.includes('€')),
      url: cleanUrl(urlMatch[1]),
      via: 'xing'
    };
  }

  // ── INDEED ──────────────────────────────────────────────────────────────
  else if (blockText.includes('indeed.com') || blockText.includes('Wir glauben')) {
    const metaMatch = blockText.match(/passt:\s*(.+?)\s+bei\s+(.+?)\s+in\s+(.+?)\./i);
    const urlMatch = block.match(/(https:\/\/cts\.indeed\.com\/\S+)/);

    if (metaMatch && urlMatch) {
      extracted = {
        title: metaMatch[1],
        company: metaMatch[2],
        location: metaMatch[3],
        url: cleanUrl(urlMatch[1]),
        via: 'indeed'
      };
    }
  }

  // ── Validation, Mapping & Null Enforcement ───────────────────────────────
  if (extracted.title && extracted.url) {
    const isNoise = noisePhrases.some(phrase => extracted.title.toLowerCase().includes(phrase));

    if (!isNoise && extracted.title.length > 3 && !seenUrls.has(extracted.url)) {
      seenUrls.add(extracted.url);

      jobs.push({
        json: {
          company:       extracted.company || null,
          email:         null, // Not available in standard newsletter text
          title:         extracted.title || null,
          url:           extracted.url || null,
          description:   null, // Requires scraping the destination URL
          location:      extracted.location || null,
          salary:        extracted.salary || null,
          schedule_type: null, // Requires scraping the destination URL
          posted,
          via:           extracted.via || null
        }
      });
    }
  }
}

return jobs.length > 0 ? jobs : [{ json: { _debug: "No valid jobs found" } }];
